using System.Collections;
using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Tarefa #7 — Diabo-da-Tasmânia: rodopio ofensivo. Enquanto gira no lugar
/// (no chão, movimento bloqueado), causa dano em área a intervalos
/// regulares a todos os inimigos dentro de spinAttackRadius.
/// </summary>
[RequireComponent(typeof(PlayerMotor2D))]
public class SpinAttackAbility : MonoBehaviour, IFormAbility, IAbility, IActiveAbility
{
    private const int MaxHits = 8;
    private static readonly Collider2D[] HitBuffer = new Collider2D[MaxHits];

    private bool enabledForForm;
    private AnimalFormData form;
    private PlayerMotor2D motor;

    private float cooldownTimer;
    private Coroutine spinRoutine;

    /// <summary>true enquanto o rodopio está em curso.</summary>
    public bool IsSpinning => spinRoutine != null;

    private void Awake()
    {
        motor = GetComponent<PlayerMotor2D>();
    }

    private void Update()
    {
        if (cooldownTimer > 0f) cooldownTimer -= Time.deltaTime;
    }

    public void ConfigureFromForm(AnimalFormData newForm)
    {
        form = newForm;
        enabledForForm = form != null && form.primaryAbility == PrimaryAbility.SpinAttack;
        if (!enabledForForm) StopSpinIfRunning();
    }

    /// <summary>Chamado pelo AbilityRouter (botão de Habilidade).</summary>
    public void TrySpin()
    {
        if (!enabledForForm || cooldownTimer > 0f || spinRoutine != null) return;
        if (motor.MovementLocked || !motor.IsGrounded) return;
        // GDD: enquanto invisível (Pó Dourado) o player não causa dano.
        if (PlayerConsumableEffects.Instance != null && PlayerConsumableEffects.Instance.IsInvisible) return;

        spinRoutine = StartCoroutine(SpinRoutine());
    }

    private IEnumerator SpinRoutine()
    {
        cooldownTimer = form.spinAttackCooldown;

        motor.SetMovementLocked(true, this);
        motor.Anim?.SetBool("IsSpinning", true);

        var hitEnemies = new HashSet<EnemyHealth>();
        float elapsed = 0f;
        float tickTimer = 0f;

        while (elapsed < form.spinAttackDuration)
        {
            tickTimer -= Time.deltaTime;
            if (tickTimer <= 0f)
            {
                tickTimer = Mathf.Max(0.05f, form.spinAttackTickInterval);
                hitEnemies.Clear();
                HitNearbyEnemies(hitEnemies);
            }

            elapsed += Time.deltaTime;
            yield return null;
        }

        EndSpin();
    }

    private void HitNearbyEnemies(HashSet<EnemyHealth> hitThisTick)
    {
        // GDD: enquanto invisível (Pó Dourado) o player não causa dano.
        if (PlayerConsumableEffects.Instance != null && PlayerConsumableEffects.Instance.IsInvisible) return;

        int count = Physics2D.OverlapCircleNonAlloc(transform.position, form.spinAttackRadius, HitBuffer);
        for (int i = 0; i < count; i++)
        {
            var col = HitBuffer[i];
            if (col == null) continue;

            var enemyHealth = col.GetComponentInParent<EnemyHealth>();
            if (enemyHealth == null || !hitThisTick.Add(enemyHealth)) continue;

            enemyHealth.TakeDamage(form.spinAttackDamage, form.categories, transform.position, form.spinAttackKnockback);
        }
    }

    private void EndSpin()
    {
        motor.Anim?.SetBool("IsSpinning", false);
        motor.SetMovementLocked(false, this);
        spinRoutine = null;
    }

    private void StopSpinIfRunning()
    {
        if (spinRoutine == null) return;
        StopCoroutine(spinRoutine);
        EndSpin();
    }

    public void Cancel(AbilityCancelReason reason) => StopSpinIfRunning();

    void IAbility.Activate() => TrySpin();
    void IAbility.Release() { }
    public float CooldownRemaining => Mathf.Max(0f, cooldownTimer);
    bool IAbility.IsActive => spinRoutine != null;
    public float CooldownDuration => form != null ? form.spinAttackCooldown : 0f;
    public bool CanActivate => enabledForForm && cooldownTimer <= 0f && spinRoutine == null && !motor.MovementLocked && motor.IsGrounded;
    public void ResetCooldown() => cooldownTimer = 0f;
}
